const raw = $json.stdout || $json.data || $json.response || '';
const now = new Date().toISOString();
const reboot = /reboot_required=yes/.test(raw);
const unattended = /active/.test(raw);
const upgradable = (raw.match(/^\w.+\/.+$/gm) || []).length;
const healthy = unattended && !reboot && upgradable === 0;
const status = healthy ? 'Healthy' : 'Needs Attention';
const emoji = healthy ? '✅' : '🚨';
const blocks = [ { type: 'header', text: { type: 'plain_text', text: `${emoji} Healthcheck Security Audit` } }, { type: 'context', elements: [ { type: 'mrkdwn', text: `*Checked:* ${now}` }, { type: 'mrkdwn', text: `*Status:* ${status}` } ] }, { type: 'divider' }, { type: 'section', fields: [ { type: 'mrkdwn', text: `*Unattended Upgrades*\n${unattended ? 'Active' : 'Inactive'}` }, { type: 'mrkdwn', text: `*Reboot Required*\n${reboot ? 'Yes' : 'No'}` }, { type: 'mrkdwn', text: `*Upgradeable*\n${upgradable}` } ] } ];
return [{ json: { checkedAt: now, healthy, slackText: `${emoji} Healthcheck security audit: ${status}`, slackBlocks: blocks } }];
